<div class="ja">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">触媒が増えるほど、結合確率は下がる</text>
  <text x="20" y="46" fill="#a1a1aa" font-size="13" font-family="sans-serif">例:各触媒が互いに独立していると仮定した場合(70%・50%・40%)</text>
  <line x1="60" y1="330" x2="660" y2="330" stroke="#52525b" stroke-width="1"/>
  <line x1="60" y1="190" x2="660" y2="190" stroke="rgba(255,255,255,.15)" stroke-width="1" stroke-dasharray="4,3"/>
  <rect x="110" y="190" width="110" height="140" fill="#4ade80" rx="3"/>
  <text x="165" y="178" fill="#4ade80" font-size="17" font-weight="700" text-anchor="middle" font-family="sans-serif">70%</text>
